案例代码：
entity top is
port (
CLK, CTRL, D1, D2: in std_logic;
OUT1 : out std_logic;
OUT2 : out std_logic
);
end entity;

architecture basic of top is
signal and_clk : std_logic;
begin
	DFF1 : entity dff port map ( CLK => and_clk, D => D1, Q => OUT1 );
	DFF2 : entity dff port map ( CLK => CLK, D => D2, Q => OUT2 );
	and_clk <= CTRL and CLK;		//全局时钟“CLK”通过了门控，只要有可能就不要将门控时钟用在FPGA中，因为这样的设计进行时钟延迟和偏斜的细调会变得很困难
end architecture;

案例代码：
entity sr is
port (
	clk, reset, data_a, data_b: in std_logic;
	Q: out std_logic
 );
end;
architecture rtl of sr is
signal trf12: std_logic;
begin
process ( trf12, reset ) begin
if reset = '1' then
	Q <= '0';
elsif (trf12'event and trf12='1') then
	Q <= data_b;                     //触发器的时钟端“sr.Q”被另一触发器的输出所驱动。时钟树综合工具将无法考虑时钟的平衡
end if;
end process;
process ( clk, reset ) begin
if reset = '1' then
	trf12 <= '0';
elsif (clk'event and clk='1') then
	trf12 <= data_a;              //时钟端由触发器“sr.trf12”所驱动
end if;
end process;
end;

案例代码：
entity dff is
port (
	clk_a, clk_b: in std_logic;
	data: std_logic;
	Q1, Q2: out std_logic
 );
end;
architecture rtl of top is
begin
process( clk_a )
begin
-- clk_a is auto-detected as the clock signal
if (clk_a'event and clk_a='1') then
	Q1 <= data;
end if;
end process;
process( clk_b )
begin
if (clk_b'event and clk_b='1') then
	Q2 <= clk_a;                             //将时钟信号连接至触发器的非时钟端将导致时序分析错误,全局时钟信号“clk_a”被连接至触发器“Q2”的数据输入端
end if;
end process;
end;

案例代码：  
entity dff is
port (...
	reset: in std_logic;
	...
	);
end entity dff;
architecture rtl of dff is
begin
	...
process( reset )           //全局复位“dff.reset”被连接到时钟端。全局复位宜直接连接到复位端作为复位使用
begin
if rising_edge( reset ) then
	Q <= data;
end if;
end process;
	...
end architecture rtl；

案例代码：
entity dff is
port (
	clk, reset_a, reset_b, data: in std_logic;
	Q: out std_logic
);
end entity dff;
architecture rtl of dff is
signal rst_gen: std_logic;
begin
	rst_gen <= reset_a xor reset_b;
process ( clk, rst_gen ) begin
if rst_gen = '1' then
	Q <= '0';
elsif ( clk'event and clk='1' ) then
	Q <= data;
end if;

案例代码：
process (clk, reset, set) begin //触发器q引用了两个异步置位和异步复位控制。推荐使用单独的异步复位控制。
if ( reset = '1' ) then   //异步复位控制。
  q <= '0';
elsif ( set= '1' ) then   //异步置位控制。
  q <= '1';
elsif ( clk'event and clk = '1' ) then
  q <= data;
end if;
end process;

案例代码：
entity top is
port (
	  in1, in2, in3, clk1, clk2, reset, sel : in std_logic; //信号“clk1”被同时用作时钟和复位。不要混合使用时钟和复位以免DFT产生问题，此时扫描会排除所有时钟信号连接的部分。
	  out1, out2 : out std_logic
	  );
end entity;
architecture top_rtl of top is
signal mux_to_ff1, mux_to_ff2 : std_logic;
begin
 mux_to_ff2 <= clk1 when sel = '1' else
  in3;
 MUX_INSTANCE : entity mux port map ( in1 =>
clk1, in2 => in2 , sel => sel, out1 => mux_to_ff1
);
 DFF_INSTANCE1 : entity dff port map ( D => in1, CLK => mux_to_ff1, RESET => reset , Q => out1 ); //连接到“top. DFF_INSTANCE1”时钟端。
 DFF_INSTANCE2 : entity dff port map ( D => in1, CLK => clk2, RESET => mux_to_ff2, Q => out2 ); //连接到“top. DFF_INSTANCE2”异步复位端。
end architecture;

