案例代码：
entity mux2x1 is
port (
	IN1, IN2, SEL: in std_logic;
	Q: out std_logic
);
end entity;
architecture basic of mux2x1 is
begin
process ( SEL, IN1, IN2 ) is
begin
if ( SEL = 2 ) then                       //条件不可达
	Q <= IN1;
else
	Q <= IN2;
	end if;
end process;
end architecture;

案例代码：
library ieee;
use ieee.std_logic_1164.all;
entity top is
port (
	  in1, enb: in std_logic;
	  out_data: out std_logic;
	  io: inout std_logic
);
end entity;
architecture RTL of top is
begin
  io <= in1;       //inout 端口io 不应直接连接到输入端口in1。
  out_data <= io;  //inout 端口io 不应直接连接到输出端口out_data。
end architecture;

案例代码：
entity top is
port(
	 data: in std_logic_vector(1 downto 0);
	 sel: in std_logic;
	 Q: inout std_logic
	);
end entity;

architecture rtl of top is
signal temp: std_logic_vector(2 downto 0);
begin
	 temp(0)<=data(0) and temp(2);
	 temp(1)<=temp(0) xor data(1);
	 temp(2)<=data(0) when sel = '0' else temp(1);		//在信号线“temp(2)”检测到组合电路反馈，为避免时序分析时产生反馈循环，不要在组合电路中使用反馈
	 Q <= temp(2);
end;

案例代码：
process ( SEL, X_IN, Z_IN, TMP_STORAGE ) begin       //不宜在同一个顺序块中描述2 个或更多的if 或case 语句
if( SEL = '1' ) then                                 //if 语句在顺序块中
	TMP_STORAGE <= X_IN + Z_IN;
else
	TMP_STORAGE <= X_IN - Z_IN;
end if
LO_B = TMP_STORAGE[31];
if( TMP_STORAGE(7 downto 0) = X"00" ) then       //if 语句在同一个顺序块中
	Z_REG <= '1';
else
	Z_REG <= '0';
end if
if( LO_B = '1' and Z_REG = '0' ) then                //if 语句在同一个顺序块中
	X_REG <= '1';
else
	X_REG <= '0';
end if
	R_REG <= TMP_STORAGE(30 downto 0);
end process

